import se.skl.rivta.testsupport.soapui.datasource.XmlDataReader
import com.eviware.soapui.support.GroovyUtils

def utils = new GroovyUtils(context)
def dataFile = new File(utils.projectPath + "/data.xml")

def callerName = testRunner.testCase.getName()
//log.info("Namn = " + callerName)
log.info(testRunner.testCase.getName())
if (testRunner.testCase.getPropertyValue("callerName") != null && testRunner.testCase.getPropertyValue("callerName") != '')
{
	//Anrop från annat testfall
	callerName = testRunner.testCase.getPropertyValue("callerName")
	log.info("Externt anrop från " + callerName)
}
def source = new XmlDataReader(context, dataFile)
source.load(callerName)
testRunner.testCase.setPropertyValue("callerName", null)

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

context.allRecords = ca.getContentRecords()

con:config.script:
def documentTime = '/urn:maternityMedicalRecord/urn1:maternityMedicalRecordHeader/urn1:documentTime'
def authorTime = '/urn:maternityMedicalRecord/urn1:maternityMedicalRecordHeader/urn1:accountableHealthcareProfessional/urn1:authorTime'
def signatureTime = '/urn:maternityMedicalRecord/urn1:maternityMedicalRecordHeader/urn1:legalAuthenticator/urn1:signatureTime'

if (!context.allRecords) {
	testRunner.fail("No records")
	return
}

if (!context.dates) {
	def documentTimes = context.allRecords.collect { record -> record.firstElementAt(documentTime) }
	def authorTimes = context.allRecords.collect { record -> record.firstElementAt(authorTime) }
	def signatureTimes = context.allRecords.collect { record -> record.firstElementAt(signatureTime) }

	context.dates = documentTimes.findAll().collect{ it[0..7] }.unique()
	context.dates += authorTimes.findAll().collect{ it[0..7] }.unique()
	context.dates += signatureTimes.findAll().collect{ it[0..7] }.unique()

	context.dates = context.dates.findAll().collect{ it[0..7] }.unique()
	log.info "Unika datum: " + context.dates

	if (!context.dates) {
		testRunner.fail("No data")
	}
}

context.timePeriodStart = context.dates.pop()
context.timePeriodEnd = context.timePeriodStart

[context.timePeriodStart, context.timePeriodEnd]

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

def documentTime = '/urn:maternityMedicalRecord/urn1:maternityMedicalRecordHeader/urn1:documentTime'
def authorTime = '/urn:maternityMedicalRecord/urn1:maternityMedicalRecordHeader/urn1:accountableHealthcareProfessional/urn1:authorTime'
def signatureTime = '/urn:maternityMedicalRecord/urn1:maternityMedicalRecordHeader/urn1:legalAuthenticator/urn1:signatureTime'
def id = '/urn:maternityMedicalRecord/urn1:maternityMedicalRecordHeader/urn1:documentId'

def condition = { record ->
	def documentTimeWithin = record.firstElementAt(documentTime) != null && record.timestampInRange(documentTime, context.timePeriodStart + '000000', context.timePeriodEnd + '235959')
	def authorTimeWithin = record.timestampInRange(authorTime, context.timePeriodStart + '000000', context.timePeriodEnd + '235959')
	def signatureTimeWithin = record.firstElementAt(signatureTime) != null && record.timestampInRange(signatureTime, context.timePeriodStart + '000000', context.timePeriodEnd + '235959')

	return (documentTimeWithin || authorTimeWithin || signatureTimeWithin)
}

def recordInfo = { record ->
	sprintf("DocumentId %s (authorTime:%s documentTime:%s signatureTime:%s)", [id, authorTime, documentTime, signatureTime].collect{record.firstElementAt(it)})
}

ca.assertFilteredResponse(context.allRecords, condition, recordInfo)

con:config.script:
if (context.dates.any()) {
	testRunner.gotoStepByName( "Calculate interval")
}
else if (testRunner.getResults().any{it.getStatus().toString() == 'FAILED'}) {
	testRunner.fail("One or more steps failed")
}

