import se.skl.rivta.testsupport.soapui.datasource.XmlDataReader
import com.eviware.soapui.support.GroovyUtils

def utils = new GroovyUtils(context)
def dataFile = new File(utils.projectPath + "/data.xml")
def source = new XmlDataReader(context, dataFile)

source.load(testRunner.testCase.getName())

//Förbered för anrop av 1.2.1
testRunner.testCase.testSteps["Run TestCase 1.2.1"].setPropertyValue("callerName",testRunner.testCase.getName());

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

def authorTime = '/urn:maternityMedicalRecord/urn1:maternityMedicalRecordHeader/urn1:accountableHealthcareProfessional/urn1:authorTime'
def documentTime = '/urn:maternityMedicalRecord/urn1:maternityMedicalRecordHeader/urn1:documentTime'
def signatureTime = '/urn:maternityMedicalRecord/urn1:maternityMedicalRecordHeader/urn1:legalAuthenticator/urn1:signatureTime'
def id = '/urn:maternityMedicalRecord/urn1:maternityMedicalRecordHeader/urn1:documentId'

def condition = { record ->
	// Starttidpunkt = documentTime och  Sluttidpunkt = authorTime
	def hasDocumentTime = record.firstElementAt(documentTime)
	def hasAuthorTime = record.firstElementAt(authorTime)
	def hasSignatureTime = record.firstElementAt(signatureTime)
	//log.info("hasDocumentTime:" + hasDocumentTime + "hasAuthorTime:" + hasAuthorTime + "hasSignatureTime:" + hasSignatureTime)

	return hasDocumentTime <= hasSignatureTime
}
def recordInfo = sprintf("Testdata saknas för testfall 8.1")
ca.assertForAnyRecord(condition, recordInfo)
